#include "tds_meter.h"
#include <Arduino.h>
#define TDS_PIN 34
static float _ppm=0,_v=0;static unsigned long _l=0;
void tds_setup(){pinMode(TDS_PIN,INPUT);Serial.println("[tds] OK");}
void tds_loop(){if(millis()-_l<1000)return;_l=millis();int r=0;for(int i=0;i<10;i++)r+=analogRead(TDS_PIN);_v=r/10.0*3.3/4095.0;float comp=_v*(1.0+0.02*(25.0-25.0));_ppm=(133.42*comp*comp*comp-255.86*comp*comp+857.39*comp)*0.5;}
float tds_get_ppm(){return _ppm;}
float tds_get_voltage(){return _v;}
